const input = $json;
if (!input.agent_role) throw new Error('agent_role is required');
if (input.decision === undefined || input.decision === null) throw new Error('decision is required');

// Ensure decision is always a JSON-serializable object
const decisionObj = typeof input.decision === 'string'
  ? (() => { try { return JSON.parse(input.decision); } catch(e) { return { raw: input.decision }; } })()
  : (input.decision || {});

// Ensure context_used and evidence are objects
const contextUsed = typeof input.context_used === 'string'
  ? (() => { try { return JSON.parse(input.context_used); } catch(e) { return {}; } })()
  : (input.context_used || {});

const evidence = typeof input.evidence === 'string'
  ? (() => { try { return JSON.parse(input.evidence); } catch(e) { return {}; } })()
  : (input.evidence || {});

return [{
  json: {
    ...input,
    correlation_id: input.correlation_id || `ai-${Date.now()}`,
    decision_type: input.decision_type || 'general',
    risk_level: input.risk_level || 'low',
    confidence: parseFloat(input.confidence) || 1.0,
    requires_human_approval: !!input.requires_human_approval,
    status: input.requires_human_approval ? 'pending_approval' : 'approved',
    decision: decisionObj,
    context_used: contextUsed,
    evidence
  }
}];

const decisionId = $json.decision_id;
const role = $('Validate & Format').item.json.agent_role;
const recommendation = $('Validate & Format').item.json.recommendation;
const risk = $('Validate & Format').item.json.risk_level;

const content = `⚠️ **Aprobación de IA Requerida**\nEl agente **${role}** ha propuesto una acción de riesgo **${risk}**.\n\n**Recomendación:** ${recommendation}\n\nID: \`${decisionId}\`\n*(Responde \`!aprobar ${decisionId}\` para autorizar)*`;

return [{
  json: {
    outbox_target: 'discord',
    outbox_action: 'notify',
    outbox_payload: { content },
    correlation_id: $('Validate & Format').item.json.correlation_id
  }
}];
